import './Stats.css'

const stats = [
    { number: '23K+', label: 'Активних користувачів' },
    { number: '45K+', label: 'Підключених рахунків' },
    { number: '15K+', label: 'Інвест-портфелів' },
    { number: '225K+', label: 'Успішних транзакцій' },
]

const Stats = () => {
    return (
        <section className="stats" id="stats">
            <div className="stats-container">
                {stats.map((item, index) => (
                    <div className="stat" key={index}>
                        <div className="stat-number">{item.number}</div>
                        <div className="stat-label">{item.label}</div>
                    </div>
                ))}
            </div>
            <div className="stats-footnote">*Дані за 2025 рік</div>
        </section>
    )
}

export default Stats
